+	}
+	if limit <= 0 {
+		limit = 100
+	}
+
+	events := make([]state.StoredAttentionEvent, 0, len(s.events))
+	for _, event := range s.events {
+		if event.Ts.Before(start) || event.Ts.After(end) {
+			continue
+		}
+		events = append(events, event)
+		if len(events) == limit {
+			break
+		}
+	}
+	return events, nil
+}
